"use strict";(self["webpackChunkfrontend"]=self["webpackChunkfrontend"]||[]).push([[578],{8197:function(n,r,e){e.r(r),e.d(r,{default:function(){return w}});var l=e(6436),s=e(7959);const t={class:"role-model-page"},a={class:"table-scroll"},b={class:"role-table"},o={class:"col-name"},c={class:"col-stage"},u={class:"col-level"},d={class:"col-why"},i={class:"col-focus"},m=["innerHTML"],k={class:"col-comm"},L=["innerHTML"],v={class:"col-status"};function h(n,r,e,h,f,y){return(0,l.uX)(),(0,l.CE)("div",t,[r[1]||(r[1]=(0,l.Lk)("header",{class:"page-header"},[(0,l.Lk)("h1",null,"Фреймворк и управление"),(0,l.Lk)("h2",null,"Ролевая модель")],-1)),(0,l.Lk)("div",a,[(0,l.Lk)("table",b,[r[0]||(r[0]=(0,l.Lk)("thead",null,[(0,l.Lk)("tr",null,[(0,l.Lk)("th",null,"Название роли"),(0,l.Lk)("th",null,"Этап рассмотрения на КПП"),(0,l.Lk)("th",null,"Уровень роли"),(0,l.Lk)("th",null,"Зачем? (функция полезности)"),(0,l.Lk)("th",null,"Фокус и Функции"),(0,l.Lk)("th",null,"Коммуникации (с кем и по каким вопросам)"),(0,l.Lk)("th",null,"Статус рассмотрения / утверждения роли")])],-1)),(0,l.Lk)("tbody",null,[((0,l.uX)(!0),(0,l.CE)(l.FK,null,(0,l.pI)(f.roles,((n,r)=>((0,l.uX)(),(0,l.CE)("tr",{key:r},[(0,l.Lk)("td",o,(0,s.v_)(n.name),1),(0,l.Lk)("td",c,(0,s.v_)(n.stage),1),(0,l.Lk)("td",u,(0,s.v_)(n.level),1),(0,l.Lk)("td",d,(0,s.v_)(n.why),1),(0,l.Lk)("td",i,[(0,l.Lk)("div",{innerHTML:n.focus},null,8,m)]),(0,l.Lk)("td",k,[(0,l.Lk)("div",{innerHTML:n.communications},null,8,L)]),(0,l.Lk)("td",v,(0,s.v_)(n.status),1)])))),128))])])])])}var f={name:"RoleModel",data(){return{roles:[{name:"Владелец продукта (обязательная роль для команды любого типа)",stage:"1",level:"Команда",why:"Обеспечивает развитие Продукта и максимизацию ценности. Отвечает за соответствие бэклога команды потребностям клиентов и заинтересованных лиц. Отвечает за достижение бизнес-метрик и метрик производства.",focus:"Фокус: Управление Продуктом, бэклогом Продукта<br>\n• Управление Продуктом, бэклогом Продукта. Формирует стратегию развития Продукта<br>\n• Определяет требования к Продукту, составляет дорожную карту Продукта<br>\n• Определяет цели и бизнес-метрики Продукта, обеспечивает выполнение целей Стрима/Домена (для платформенных команд бизнес-метрики не определяются)<br>\n• Определяет цели спринта, приоритизирует инициативы<br>\n• Управляет мастер-бэклогом Продукта<br>\n• Формулирует продуктовые гипотезы и обеспечивает их проверку (для продуктовых команд, для остальных типов команд — опционально)<br>\n• Выстраивает процесс discovery (для продуктовых команд, для остальных типов команд — опционально)<br>\n• Квартальное планирование. Отвечает за формирование бэклога Продукта и цели, разрешение вопросов, связанных с приоритетами работ<br>\n• Презентует планы менеджменту по окончании планирования (за исключением платформенных команд)<br>\n(Предложение от А. Делиева от 18.09.2025: добавить для Platform Owner: контроль исполнения технического долга в рамках установленных квот и участие в их приоритизации)",communications:"Заказчиком: получение уточнений по инициативе и требованиям при необходимости (первичная проработка инициативы); согласование приоритетов и последовательности реализации инициатив<br>\nВладельцем Стрима / Домена или CTO (для платформенных команд): синхронизация стратегии развития Продукта и целей Продукта; синхронизация приоритетов инициатив в рамках Стрима/Домена<br>\nДругими Владельцами продукта: синхронизация по зависимостям<br>\nМенеджером продукта/dPO: приоритизация целей и бэклога по спринтам; получение статусов реализации инициатив Продукта",status:"Рассмотрено на КПП"},{name:"Менеджер продукта / dPO (обязательная роль для команды любого типа)",stage:"1",level:"Команда",why:"Обеспечивает прозрачность и реализацию бэклога продукта. Отвечает за достижение бизнес-метрик и метрик производства.",focus:"Фокус: Управление спринт-бэклогом, управление реализацией (delivery), управление командой, эффективность производственного процесса, организация 3-ей линии поддержки<br>\n• Управление спринт-бэклогом: формирует и приоритизирует спринт-бэклог<br>\n• Управление реализацией (delivery): обеспечивает процесс доставки ценности до production в спринтах; обеспечивает достижение бизнес-метрик; отвечает за эффективность координации внутри команд и между командами<br>\n• Управление командой: организовывает планирование работы команды<br>\n• Эффективность производственного процесса: осуществляет мониторинг производственных метрик<br>\n• Квартальное планирование: отвечает за формирование планов согласно обозначенным целям, декомпозицию бэклога, вскрытие и разрешение зависимостей с другими командами в процессе планирования, обнаружение и фиксацию рисков; консультирует команды по элементам бэклога<br>\n• Организация 3-ей линии поддержки",communications:"Владельцем продукта: приоритизация целей и бэклога по спринтам; предоставление статусов реализации инициатив Продукта<br>\nТехническим лидером команды, ИТ-лидером Стрима (если команда в Стриме): по вопросам технологических решений, подходов и рисков<br>\nУчастниками команды: декомпозиция и оценка задач, получение статусов реализации<br>\nМенеджерами продуктов/dPO смежных команд: синхронизация по зависимостям<br>\nСкрам-мастером / SDM: получение статусов по уровню зрелости команд, соблюдение стандартов производства и информирование по отклонениям",status:"Рассмотрено на КПП"},{name:"Технический лидер (обязательная роль для команды любого типа)",stage:"1",level:"Команда",why:"Обеспечивает качество технической реализации на уровне команды. Отвечает за достижение бизнес-метрик и метрик производства.",focus:"Фокус: выбор способа реализации и обеспечение качества технологических решений<br>\n• Осуществляет выбор способа технической реализации решений<br>\n• Обеспечивает разработку и интеграцию решений в команде в соответствии с принятыми технологическими решениями<br>\n• Внедрение и совершенствование инженерных практик",communications:"Менеджером продукта/dPO: оптимальный путь для работы с техническими ограничениями и выбор способа технической реализации; приоритизация, пересмотр и соблюдение квоты, включение в бэклог команды технического долга; консультирование по декомпозиции задач<br>\nSolA / Директором по технологиям: согласование архитектурных решений<br>\nУчастниками команды: предоставление консультаций другим участникам команды (опционально)<br>\nИТ-лидером Стрима (если команда в Стриме): совместное формирование технологических целей, согласование ключевых технологических решений",status:"Рассмотрено на КПП"},{name:"Скрам-мастер",stage:"1",level:"Команда",why:"Обеспечивает эффективность и постоянное совершенствование процесса работы команды в соответствии с выбранной методологией производства.",focus:"• Фасилитирует все мероприятия уровня команды<br>\n• Обучает участников команды принципам цифрового производства<br>\n• Разрабатывает процедуры обмена знаниями и экспертным опытом в пределах команды<br>\n• Выявляет проблемы, а также примеры успешной работы команды<br>\n• Поддерживает координацию и синхронизацию между командами (при необходимости)<br>\n• Отслеживает прогресс и достижения целей команды в рамках ежедневных встреч<br>\n• Обеспечивает запуск процесса цифрового производства новых команд",communications:"Участниками команды, Техническим лидером: обучение принципам цифрового производства; фасилитация всех церемоний команды; обеспечение запуска новых команд<br>\nМенеджером продукта/dPO, ИТ-лидером Стрима, Директором по производству: предоставление статусов по уровню зрелости команд, соблюдение стандартов производства и информирование по отклонениям<br>\nДругими скрам-мастерами и SDM: координация команд на планировании",status:"Рассмотрено на КПП"},{name:"Участники команды",stage:"1",level:"Команда",why:"Отвечают за качество реализации элементов бэклога команды в зоне своих компетенций.",focus:"Анализ и планирование: проводят анализ и оценку по инициативам, участвуют в их декомпозиции<br>\nРазработка ПО: осуществляют разработку и интеграцию решений в соответствии с утверждённой архитектурой; отслеживают качество кода и его соответствие применимым стандартам<br>\nТестирование, поддержка и документирование: осуществляют разработку тест-кейсов и проведение различных видов тестирования; участвуют в обеспечении 3-ей линии поддержки; готовят документацию по ПО для разработанных компонентов (при необходимости)",communications:"Менеджером продукта/dPO: декомпозиция и оценка задач, предоставление статусов реализации<br>\nТехническим лидером: получение консультаций (опционально)<br>\nСкрам-мастером / SDM: обучение принципам цифрового производства; обеспечение запуска процесса цифрового производства новых команд; фасилитация Скрам-мастером всех церемоний команды<br>\nDevOps: консультации по релизам и эксплуатации; доставка кода до production-среды и тестовой среды; обучение методологии и инструментам CI/CD<br>\nSRE: обучение практикам надёжности<br>\nSolA: доведение до команды принятых технических и архитектурных решений; консультирование по вопросам возможных вариантов и подходов к реализации; архитектурный контроль",status:"—"},{name:"Заказчик",stage:"1",level:"—",why:"Отвечает за формирование инициативы с максимальной ценностью.",focus:"• Формулирует требования и заводит инициативу в систему таск-трэкинга<br>\n• Организовывает реализацию мероприятий, не связанных с ИТ-доработками систем<br>\n• Информирует пользователей о внедрённой инициативе<br>\n• При необходимости организовывает разработку программы обучения и проведение обучения<br>\n• Проводит расчёты с подрядчиком в части договоров в зоне ответственности Заказчика<br>\nДополнительно для инициатив, классифицированных как проект: осуществляет ОПЭ и приемку результатов проекта, подтверждает его закрытие; оценивает уровень удовлетворённости в рамках реализации проекта",communications:"Владельцем продукта: получение требований от заказчика по инициативе; согласование приоритета и последовательности реализации инициативы<br>\nРуководителем проекта (для инициатив, классифицированных как проект): получение требований от заказчика по проекту; формирование календарно-ресурсного планирования; организация ОПЭ и приемки результатов проекта; сбор обратной связи от заказчика по проекту",status:"Рассмотрено на КПП"},{name:"Владелец Стрима",stage:"2",level:"Стрим",why:"Отвечает за прозрачность бэклога продуктов Стрима и его приоритезацию, за управление рисками продуктов Стрима, за соответствие бэклога Стрима бизнес-целям Домена.",focus:"Фокус: Управление стратегией развития Стрима, Управление мастер-бэклогом Стрима<br>\n• Управление стратегией развития Стрима: формирует стратегию развития группы Продуктов, входящих в Стрим; определяет долгосрочное видение и дорожную карту развития Стрима; формирует цели и ключевые результаты Стрима, контролирует их выполнение; синхронизирует и приоритизирует инициативы Стрима; выявляет, анализирует и минимизирует риски, связанные с продуктами Стрима<br>\n• Управляет мастер-бэклогом Стрима",communications:"Заказчиками: управление ожиданиями и формирование стратегии развития группы Продуктов, входящих в Стрим<br>\nВладельцем домена / Диджитал лидером Домена: синхронизация целей и стратегии развития Стрима со стратегией и целями Домена<br>\nИТ-лидером Стрима: принятие ключевых решений по Стриму на два «ключа»<br>\nSDM: предоставление статусов по уровню зрелости команд, соблюдение стандартов производства и информирование по отклонениям<br>\nВладельцами продуктов: синхронизация стратегии развития и целей Продукта в рамках Стрима; синхронизация приоритетов инициатив в рамках Стрима<br>\nДругими Владельцами Стримов: реализация задач, затрагивающих продукты более чем одного Стрима в рамках домена",status:"Рассмотрено CTO, бизнес-подразделениями, необходимо согласовать учёт замечаний с УЕЦИ"},{name:"ИТ-лидер Стрима",stage:"2",level:"Стрим",why:"Обеспечивает соблюдение производственных метрик и качества производственного процесса команд в рамках Стрима. Отвечает за синхронизацию работ между Командами, контроль исполнения технического долга.",focus:"Фокус: Формирование и ресурсное наполнение команд, управление ресурсами Стрима, Эффективность производственного процесса, Выбор способа реализации и обеспечение качества технологических решений<br>\n• Формирование и ресурсное наполнение команд: запуск команд; процесс онбординга<br>\n• Управление ресурсами Стрима: обеспечение кадровыми ресурсами команд Стрима; обеспечивает процесс по планам индивидуального развития<br>\n• Эффективность производственного процесса: осуществляет мониторинг производственных метрик; контролирует соответствие целевому производственному процессу; организует и контролирует передачу знаний; согласовывает технологические планы с другими Стримами; совместно с Владельцем продукта и dPO регулирует квоты на решение технического долга, контролирует исполнение технического долга; инициирует DR-учения, тесты на проникновение (penetration tests) и тесты восстановления систем<br>\n• Выбор способа реализации и обеспечение качества технологических решений; управление ИТ-инфраструктурой; инициирует запрос на масштабирование и расширение текущей ИТ-инфраструктуры",communications:"CTO / Директором по производству / Директором по технологиям: совместное формирование технологических целей, согласование ключевых технологических решений; внедрение и совершенствование инженерных практик<br>\nВладельцем Стрима: принятие ключевых решений по Стриму на два «ключа»<br>\nSDM, Скрам-мастером: предоставление статусов по уровню зрелости команд, соблюдение стандартов производства и информирование по отклонениям; проблемные точки команд внутри Стрима<br>\nМенеджером продуктов/dPO: технологические решения, подходы и риски; приоритизация технического долга, оптимальные способы реализации<br>\nАрхитектором решения: консультации по архитектурным вопросам",status:"Рассмотрено CTO, бизнес-подразделениями, необходимо согласовать учёт замечаний с УЕЦИ"}]}}},y=e(5932);const O=(0,y.A)(f,[["render",h],["__scopeId","data-v-6671daef"]]);var w=O}}]);
